const intentAgent = await $createAgent({
  name: 'Email Intent Detector',
  model: 'gpt-4o-mini',
  tools: [
    {
      name: 'classify_intent',
      description: 'Classify email intent and extract parameters',
      parameters: {
        type: 'object',
        properties: {
          intent: { type: 'string', enum: ['reply', 'forward', 'schedule', 'delegate'] },
          priority: { type: 'string' },
          recipient_domain: { type: 'string' }
        }
      }
    }
  ]
});

const result = await intentAgent.process([
  {
    role: 'user',
    content: `Email: ${$input.email.body}
Classify intent and extract: priority, recipient domain`
  }
]);

return { intent: result.intent, priority: result.priority };

const draftAgent = await $createAgent({
  name: 'Draft Generator',
  model: 'gpt-4o',
  systemMessage: `You are a professional email assistant. Generate appropriate responses:
- Match original email tone
- Never include confidential info
- Use correct recipient addressing`
});

const draft = await draftAgent.process([
  {
    role: 'user',
    content: `Original: ${$input.email.body}
Intent: ${$input.intent}
Priority: ${$input.priority}
Generate professional response:`
  }
]);

return {
  subject: `Re: ${$input.email.subject}`,
  body: draft.content,
  to: $input.intent.recipient
};

const emailData = $input.draft;

// This executes WITHOUT validation in base workflow
await $sendEmail({
  to: emailData.to,
  subject: emailData.subject,
  html: emailData.body,
  attachments: $input.attachments || []
});

