import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your_project_id',
  secret: process.env.VEX_SECRET
});

const result = await vex.verify({
  input: {
    email_body: $input.email.body,
    sender: $input.email.from,
    subject: $input.email.subject
  },
  rules: [
    {
      name: 'pii_filter',
      type: 'pii_detection',
      threshold: 'high',
      action: 'block',
      config: { fields: ['email_body'] }
    }
  ]
});

if (result.valid) {
  return {
    ...$input,
    vex_score: result.score,
    redacted_body: result.output?.redacted_email_body
  };
} else {
  throw new Error(`PII detected: ${result.issues}`);
}

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'your_project_id', secret: process.env.VEX_SECRET });

const result = await vex.verify({
  input: {
    draft_body: $input.draft.body,
    recipient: $input.draft.to,
    original_email: $input.original.body,
    intent: $input.intent
  },
  rules: [
    {
      name: 'tone_check',
      type: 'sentiment_analysis',
      threshold: 'medium',
      action: 'flag',
      config: { min_positivity: 0.3, max_categories: ['hate_speech'] }
    },
    {
      name: 'recipient_validation',
      type: 'domain_allowlist',
      action: 'block',
      config: { allowed_domains: ['company.com', 'partner.org'] }
    }
  ]
});

return result.valid ? $input : { error: 'Draft validation failed', issues: result.issues };

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'your_project_id', secret: process.env.VEX_SECRET });

const finalCheck = await vex.verify({
  input: {
    final_draft: $input.draft,
    conversation_context: $input.context,
    attachments: $input.attachments,
    metadata: { priority: $input.priority, intent: $input.intent }
  },
  rules: [
    {
      name: 'confidentiality',
      type: 'content_classification',
      threshold: 'high',
      action: 'block',
      config: { prohibited: ['confidential', 'proprietary', 'internal_only'] }
    },
    {
      name: 'accuracy_check',
      type: 'factual_consistency',
      action: 'require_human'
    }
  ]
});

if (finalCheck.valid) {
  return { ...$input, approved: true, vex_final_score: finalCheck.score };
} else {
  return { ...$input, approved: false, requires_review: finalCheck.issues };
}
